  ('cpa-moex-00087', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法及相關法規規定，拍賣納稅義務人土地之價款，不足清償所有債務，有關受償 順序，下列敘述何者正確？', '["罰鍰準用有關稅捐之規定，優先普通債權受償", "以該土地設定抵押權擔保之債權，優先所得稅受償", "以該土地設定抵押權擔保之債權，優先該土地應課徵之土地增值稅受償", "營業稅欠稅，優先以該土地設定抵押權擔保之債權受償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
